package br.com.rinha.fraud.detection.engine.app.configuration;

import br.com.rinha.fraud.detection.engine.domain.entity.RiskDataEntity;
import br.com.rinha.fraud.detection.engine.domain.entity.RiskReferenceEntity;
import java.io.IOException;
import java.util.List;
import java.util.Map;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import tools.jackson.core.type.TypeReference;
import tools.jackson.databind.ObjectMapper;

@Configuration
public class InitializeConfiguration {

  @Bean("mccRiskScore")
  public Map<String, Double> initializieMccRiskScore() throws IOException {
    try (var inputStream = getClass().getResourceAsStream("/mcc_risk.json")) {
      var object = new ObjectMapper().readValue(inputStream,
          new TypeReference<Map<String, Double>>() {
          });
      return object;
    }
  }

  @Bean("riskRereference")
  public RiskDataEntity initializeScoreReference() throws IOException {
    var mapper = new ObjectMapper();
    var dim = 14;

    // Estimate size to avoid resizing - adjust if you have more/fewer records
    var estimatedSize = 1_000_000; // Based on references.json containing ~1M records
    var vectorsList = new java.util.ArrayList<float[]>(estimatedSize);
    var labelsList = new java.util.ArrayList<String>(estimatedSize);

    try (var inputStream = getClass().getResourceAsStream("/references.json")) {
      // Streaming parse to reduce memory footprint
      try (var parser = mapper.getFactory().createParser(inputStream)) {
        parser.nextToken(); // START_ARRAY

        while (parser.nextToken() != com.fasterxml.jackson.core.JsonToken.END_ARRAY) {
          var entity = parser.readValueAs(RiskReferenceEntity.class);

          float[] vector = new float[dim];
          double[] doubleVector = entity.vector();
          for (int j = 0; j < dim; j++) {
            vector[j] = (float) doubleVector[j];
          }

          vectorsList.add(vector);
          labelsList.add(entity.label());
        }
      }
    }

    var size = vectorsList.size();
    float[] vectors = new float[size * dim];
    String[] labels = new String[size];

    int index = 0;
    for (int i = 0; i < size; i++) {
      float[] vector = vectorsList.get(i);
      for (int j = 0; j < dim; j++) {
        vectors[index++] = vector[j];
      }
      labels[i] = labelsList.get(i);
    }

    return new RiskDataEntity(vectors, labels, dim);
  }
}

